import React, { useState, useContext } from 'react';
import { Pressable, SafeAreaView, ScrollView, StyleSheet, Text, TextInput, View } from 'react-native';
import { signInWithPhone } from '../services/firebaseService';
import { AuthContext } from '../../App';
import { NativeStackScreenProps } from '@react-navigation/native-stack';
import { RootStackParamList } from '../navigation/AppNavigator';
import TopNav from '../components/TopNav';

type Props = NativeStackScreenProps<RootStackParamList, 'Login'>;

const LoginScreen = ({ navigation }: Props) => {
  const [phone, setPhone] = useState('');
  const [loading, setLoading] = useState(false);
  const [errorMessage, setErrorMessage] = useState('');
  const { profile } = useContext(AuthContext);

  const handleLogin = async () => {
    if (!phone) {
      setErrorMessage('Please provide your phone number.');
      return;
    }
    setLoading(true);
    setErrorMessage('');
    try {
      await signInWithPhone(phone.trim());
    } catch (error: any) {
      const code = error?.code as string | undefined;
      if (code === 'auth/user-not-found' || code === 'auth/invalid-credential') {
        setErrorMessage('Phone number not found. Please sign up first.');
        navigation.navigate('Signup');
      } else if (code === 'auth/network-request-failed') {
        setErrorMessage('Server is offline. Please start emulators and try again.');
      } else {
        setErrorMessage(error.message || 'Unable to sign in.');
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.backgroundCircleLarge} />
      <View style={styles.backgroundCircleSmall} />
      <View style={styles.backgroundCircleTiny} />
      <TopNav />
      <ScrollView contentContainerStyle={styles.content} keyboardShouldPersistTaps="handled">
        <View style={styles.heroCard}>
          <View style={styles.logoRow}>
            <View style={styles.logoBadge}>
              <Text style={styles.logoIcon}>💧</Text>
            </View>
            <View>
              <Text style={styles.brand}>Thanni CAN</Text>
              <Text style={styles.kicker}>Water delivery made simple</Text>
            </View>
          </View>
          <Text style={styles.title}>Welcome back</Text>
          <Text style={styles.subtitle}>Sign in to manage deliveries, track orders, and update your profile.</Text>
        </View>
        <View style={styles.formCard}>
          <Text style={styles.formLabel}>Phone number</Text>
          <TextInput
            style={styles.input}
            placeholder="Phone number"
            placeholderTextColor="#8BA3BD"
            value={phone}
            keyboardType="phone-pad"
            onChangeText={setPhone}
          />
          <Text style={styles.helperText}>Use your registered number with country code, for example +91 99000 02222.</Text>
          {errorMessage ? <Text style={styles.errorText}>{errorMessage}</Text> : null}
          <Pressable
            style={({ pressed }) => [styles.button, pressed && styles.buttonPressed, loading && styles.buttonDisabled]}
            onPress={handleLogin}
            disabled={loading}
          >
            <Text style={styles.buttonText}>{loading ? 'Signing in...' : 'Sign in'}</Text>
          </Pressable>
        </View>
        <View style={styles.noteCard}>
          <Text style={styles.noteTitle}>Secure access</Text>
          <Text style={styles.noteText}>Customers can place orders after approval. Owners can manage orders and inventory.</Text>
        </View>
        <Pressable style={styles.bottomLinkButton} onPress={() => navigation.navigate('Signup')}>
          <Text style={styles.bottomLinkButtonText}>Create account</Text>
        </Pressable>
        {profile ? <Text style={styles.roleTag}>Signed in as {profile.role}</Text> : null}
      </ScrollView>
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#EFF8FF'
  },
  backgroundCircleLarge: {
    position: 'absolute',
    top: -90,
    right: -70,
    width: 240,
    height: 240,
    borderRadius: 120,
    backgroundColor: '#BDE9FF',
    opacity: 0.9
  },
  backgroundCircleSmall: {
    position: 'absolute',
    bottom: 90,
    left: -50,
    width: 150,
    height: 150,
    borderRadius: 75,
    backgroundColor: '#D8F1FF',
    opacity: 0.95
  },
  backgroundCircleTiny: {
    position: 'absolute',
    top: 120,
    left: 24,
    width: 72,
    height: 72,
    borderRadius: 36,
    backgroundColor: '#CDEBFF',
    opacity: 0.9
  },
  content: {
    flexGrow: 1,
    justifyContent: 'center',
    paddingHorizontal: 20,
    paddingVertical: 32
  },
  heroCard: {
    marginBottom: 18,
    padding: 22,
    borderRadius: 30,
    backgroundColor: 'rgba(255,255,255,0.78)',
    borderWidth: 1,
    borderColor: 'rgba(188, 228, 255, 0.9)',
    boxShadow: '0px 10px 30px rgba(140, 201, 234, 0.28)'
  },
  brand: {
    fontSize: 28,
    fontWeight: '900',
    color: '#00344B',
    lineHeight: 30
  },
  logoRow: {
    flexDirection: 'row',
    alignItems: 'center',
    gap: 12,
    marginBottom: 18
  },
  logoBadge: {
    width: 46,
    height: 46,
    borderRadius: 23,
    backgroundColor: '#DDF3FF',
    alignItems: 'center',
    justifyContent: 'center'
  },
  logoIcon: {
    fontSize: 22
  },
  kicker: {
    marginTop: 4,
    color: '#5A87A8',
    fontSize: 12,
    fontWeight: '700',
    textTransform: 'uppercase',
    letterSpacing: 0.8
  },
  title: {
    fontSize: 30,
    fontWeight: '800',
    color: '#0B2E44',
    marginBottom: 8
  },
  subtitle: {
    fontSize: 15,
    color: '#517087',
    lineHeight: 24
  },
  formCard: {
    backgroundColor: 'rgba(255,255,255,0.92)',
    padding: 20,
    borderRadius: 26,
    borderWidth: 1,
    borderColor: 'rgba(210, 232, 247, 0.95)',
    boxShadow: '0px 8px 24px rgba(140, 201, 234, 0.22)'
  },
  formLabel: {
    color: '#3A617E',
    fontSize: 13,
    fontWeight: '800',
    marginBottom: 10,
    textTransform: 'uppercase',
    letterSpacing: 0.8
  },
  input: {
    backgroundColor: '#F4FAFF',
    borderRadius: 18,
    paddingHorizontal: 16,
    paddingVertical: 15,
    marginBottom: 10,
    borderWidth: 1,
    borderColor: '#CFE6F5',
    color: '#0F172A',
    fontSize: 16
  },
  button: {
    backgroundColor: '#4CB0E6',
    borderRadius: 18,
    alignItems: 'center',
    paddingVertical: 16,
    marginTop: 8,
    boxShadow: '0px 6px 18px rgba(76, 176, 230, 0.32)'
  },
  buttonPressed: {
    backgroundColor: '#3C9FD4'
  },
  buttonDisabled: {
    opacity: 0.7
  },
  buttonText: {
    color: 'white',
    fontSize: 16,
    fontWeight: '800'
  },
  noteCard: {
    marginTop: 14,
    backgroundColor: 'rgba(230, 247, 255, 0.82)',
    borderRadius: 22,
    padding: 16,
    borderWidth: 1,
    borderColor: 'rgba(164, 218, 246, 0.9)'
  },
  noteTitle: {
    color: '#0B4A6D',
    fontWeight: '800',
    marginBottom: 6
  },
  noteText: {
    color: '#52748A',
    lineHeight: 20
  },
  bottomLinkButton: {
    marginTop: 16,
    alignItems: 'center',
    paddingVertical: 10
  },
  bottomLinkButtonText: {
    color: '#0B4A6D',
    fontWeight: '800',
    fontSize: 15
  },
  roleTag: {
    marginTop: 24,
    textAlign: 'center',
    color: '#5B7B92',
    fontWeight: '600'
  },
  helperText: {
    color: '#5C7890',
    marginBottom: 6,
    fontSize: 12,
    lineHeight: 18
  },
  errorText: {
    color: '#C2410C',
    fontWeight: '700',
    marginTop: 4,
    marginBottom: 2
  }
});

export default LoginScreen;
